// // This D flip-flop has an active-low reset and captures the input 'ip' on the falling edge of the clock signal 'clk'. The output 'q' reflects the value of 'ip' unless the reset signal 'rst' is deasserted, in which case 'q' is set to 1.
module top_module(ip,clk,rst,q,qb);input ip, clk, rst;
    output reg q;
    output qb;

    assign qb = ~q;



    always @(posedge clk) begin
        if(rst) begin
            q<=0;
        end
        else begin
            q<=ip;
        end
    end

endmodule
